fun nextPalindrome(x: Long): Long {
    if (x < 0) return 1
    val s = x.toString()
    val n = s.length
    if (n == 0) return 1
    val halfLen = (n + 1) / 2
    val left = s.substring(0, halfLen)
    val cand = buildPalindrome(left, n)
    if (cand > x) {
        return cand
    }
    val leftInc = (left.toLong() + 1).toString()
    if (leftInc.length > left.length) {
        return if (n == 1) {
            11
        } else {
            "1" + "0".repeat(n - 1) + "1".toLong()
        }
    } else {
        return buildPalindrome(leftInc, n)
    }
}

fun buildPalindrome(left: String, len: Int): Long {
    val leftPart = if (len % 2 == 1) {
        left.substring(0, left.length - 1)
    } else {
        left
    }
    val reversed = leftPart.reversed()
    return (left + reversed).toLong()
}

fun isSpecial(x: Long): Boolean {
    val s = x.toString()
    if (s.contains('0')) {
        return false
    }
    val freq = IntArray(10)
    for (c in s) {
        val digit = c - '0'
        if (digit in 1..9) {
            freq[digit]++
        }
    }
    for (digit in 1..9) {
        if (freq[digit] != 0 && freq[digit] != digit) {
            return false
        }
    }
    return true
}

fun solve(n: Long): Long {
    var candidate = nextPalindrome(n + 1)
    while (true) {
        if (isSpecial(candidate)) {
            return candidate
        }
        candidate = nextPalindrome(candidate + 1)
    }
}
```

