                total += (i + 1)
            }
        }
        if (total <= 45) {
            masksByTotal[total].add(mask)
        }
    }
    val candidates = mutableListOf<Long>()
    for (L in 1..19) {
        for (mask in masksByTotal[L]) {
            val set = mutableSetOf<Int>()
            var oddCount = 0
            var center = -1
            for (i in 0 until totalDigits) {
                if (mask and (1 shl i) != 0) {
                    val d = i + 1
                    set.add(d)
                    if (d % 2 == 1) {
                        oddCount++
                        center = d
                    }
                }
            }
            if (L % 2 == 0) {
                if (oddCount != 0) continue
            } else {
                if (oddCount != 1) continue
            }
            val multiset = mutableListOf<Int>()
            for (d in set) {
                val count = if (L % 2 == 1 && d == center) (d - 1) / 2 else d / 2
                repeat(count) {
                    multiset.add(d)
                }
