import java.util.Collections

fun solve(n: Long): Long {
    if (n == 0L) return 1

    val nStr = n.toString()
    val minLen = nStr.length
    val digits = (1..9).toList()

    val groups = (1..45).associateWith { mutableListOf<Set<Int>>() }
    val allSets = powerset(digits)
    for (set in allSets) {
        if (set.isEmpty()) continue
        val total = set.sum()
        if (total in 1..45) {
            groups[total]?.add(set)
        }
    }

    for (L in minLen..45) {
        val candidateList = mutableListOf<String>()
        for (set in groups[L] ?: continue) {
            val numOdds = set.count { it % 2 == 1 }
            if (L % 2 == 0) {
                if (numOdds != 0) continue
            } else {
                if (numOdds != 1) continue
            }
            val candidateStr = generateCandidateStr(set, L)
            if (L > minLen) {
                candidateList.add(candidateStr)
            } else {
                if (candidateStr > nStr) {
                    candidateList.add(candidateStr)
                }
            }
        }
        if (candidateList.isNotEmpty()) {
            candidateList.sort()
            return candidateList[0].toLong()
        }
    }
    return -1
}

fun powerset(list: List<Int>): List<Set<Int>> {
    val n = list.size
    val res = mutableListOf<Set<Int>>()
    for (mask in 0 until (1 shl n)) {
        val set = mutableSetOf<Int>()
        for (i in list.indices) {
            if (mask and (1 shl i) != 0) {
                set.add(list[i])
            }
        }
        res.add(set)
    }
    return res
}

fun generateCandidateStr(set: Set<Int>, L: Int): String {
    if (L % 2 == 0) {
        val list = mutableListOf<Int>()
        for (d in set) {
            repeat(d / 2) {
                list.add(d)
            }
        }
        list.sort()
        val left = list.joinToString("") { it.toString() }
        return left + left.reversed()
    } else {
        val center = set.single { it % 2 == 1 }
        val list = mutableListOf<Int>()
        for (d in set) {
            val count = if (d == center) (d - 1) / 2 else d / 2
            repeat(count) {
                list.add(d)
            }
        }
        list.sort()
        val left = list.joinToString("") { it.toString() }
        return left + center.toString() + left.reversed()
    }
}
```

